const input = $json.chatInput || $json.message || $json.text || $json.body || '';

let mensagem = '';

if (typeof input === 'string') {
  mensagem = input;
} else if (typeof input === 'object' && input !== null) {
  mensagem = input.text || input.message || input.content || JSON.stringify(input);
}

mensagem = String(mensagem)
  .replace(/\s+/g, ' ')
  .trim();

let tipo_mensagem = 'texto';

if (!mensagem) {
  mensagem = 'lead enviou mensagem vazia';
  tipo_mensagem = 'outro';
}

return [
  {
    json: {
      ...$json,
      mensagem_limpa: mensagem,
      tipo_mensagem,
      checkout_url: $json.checkout_url || 'https://cctd.convertixdigital?sck=julia10&offDiscount=JULIA10',
      cupom: $json.cupom || 'JULIA10',
      origem: $json.origem || 'chat_n8n_teste'
    }
  }
];

const raw = $json.output || $json.text || $json.response || $json.message || '';

function cleanJsonString(value) {
  return String(value)
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

let parsed = null;
let cleaned = cleanJsonString(raw);

try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (innerError) {
      parsed = null;
    }
  }
}

if (!parsed || typeof parsed !== 'object') {
  return [
    {
      json: {
        mensagem_final: 'Tive um erro aqui para te responder. Pode me mandar sua dúvida de novo?',
        etapa: 'erro',
        interesse: 'baixo',
        enviar_humano: false,
        raw_output: raw
      }
    }
  ];
}

const mensagem = parsed.mensagem || parsed.message || parsed.resposta || '';

return [
  {
    json: {
      mensagem_final: String(mensagem).trim() || 'Tive um erro aqui para te responder. Pode me mandar sua dúvida de novo?',
      etapa: parsed.etapa || '',
      interesse: parsed.interesse || '',
      enviar_humano: Boolean(parsed.enviar_humano),
      raw_output: raw
    }
  }
];

