parameters.jsCode:
const body = $json.body || {};
const conversation = body.conversation || {};
const sender = body.sender || conversation?.meta?.sender || {};
const message = Array.isArray(conversation.messages) && conversation.messages.length ? conversation.messages[0] : {};

const labelsRaw = conversation.labels || body.labels || [];
const labels = labelsRaw
  .map((label) => {
    if (typeof label === 'string') return label;
    return label?.title || label?.name || label?.label || '';
  })
  .filter(Boolean);

const requiredLabel = '40-julia-cctd';
const hasRequiredLabel = labels.includes(requiredLabel);

const event = body.event || '';
const messageType = body.message_type || '';
const contentType = body.content_type || message.content_type || '';
const content = body.content || message.content || message.processed_message_content || '';
const privateMessage = body.private === true || message.private === true;
const canReply = conversation.can_reply !== false;
const isIncoming = messageType === 'incoming' || message.message_type === 0 || message.sender_type === 'Contact';
const isText = contentType === 'text' || !!content;
const hasContent = String(content || '').trim().length > 0;

const accountId = body.account?.id || message.account_id || conversation.account_id || 1;
const conversationId = conversation.id || body.conversation_id || message.conversation_id || '';
const contactId = sender.id || conversation.contact_inbox?.contact_id || message.sender_id || '';
const inboxId = body.inbox?.id || conversation.inbox_id || message.inbox_id || '';
const phone = sender.phone_number || sender.identifier || conversation.contact_inbox?.source_id || '';
const name = sender.name || '';
const instagram = sender.additional_attributes?.social_profiles?.instagram || '';
const nicho = sender.custom_attributes?.nicho || '';

const shouldReply = Boolean(
  event === 'message_created' &&
  isIncoming &&
  !privateMessage &&
  canReply &&
  isText &&
  hasContent &&
  hasRequiredLabel
);

let blockReason = '';

if (event !== 'message_created') blockReason = 'evento_nao_e_message_created';
else if (!isIncoming) blockReason = 'mensagem_nao_incoming';
else if (privateMessage) blockReason = 'mensagem_privada';
else if (!canReply) blockReason = 'conversa_nao_permite_resposta';
else if (!isText || !hasContent) blockReason = 'sem_texto_util';
else if (!hasRequiredLabel) blockReason = 'sem_label_40_julia_cctd';

return [
  {
    json: {
      should_reply: shouldReply,
      block_reason: blockReason,
      event,
      message_type: messageType,
      content_type: contentType,
      content,
      labels,
      required_label: requiredLabel,
      account_id: accountId,
      conversation_id: conversationId,
      contact_id: contactId,
      inbox_id: inboxId,
      phone,
      name,
      instagram,
      nicho,
      sessionId: `chatwoot:account:${accountId}:conversation:${conversationId}:contact:${contactId}`,
      checkout_url: $json.checkout_url || 'https://cctd.convertix.digital?sck=julia10&offDiscount=JULIA10',
      cupom: $json.cupom || 'JULIA10',
      origem: 'chatwoot_whatsapp_cctd',
      chatwoot_base_url: 'https://chat.convertix.app',
      is_first_interaction: !body.conversation?.first_reply_created_at
    }
  }
];

